module tt_um_tensor (
	clk, 
	ena, 
	rst_n, 
	ui_in, 
	uio_in, 
	uo_out, 
	uio_out, 
	uio_oe);
   input clk;
   input ena;
   input rst_n;
   input [7:0] ui_in;
   input [7:0] uio_in;
   output [7:0] uo_out;
   output [7:0] uio_out;
   output [7:0] uio_oe;

   // Internal wires
   wire UNCONNECTED_HIER_Z;
   wire UNCONNECTED_HIER_Z0;
   wire UNCONNECTED_HIER_Z1;
   wire UNCONNECTED_HIER_Z2;
   wire UNCONNECTED_HIER_Z3;
   wire UNCONNECTED_HIER_Z4;
   wire n_0;

   assign uio_oe[0] = 1'b0 ;
   assign uio_oe[1] = 1'b0 ;
   assign uio_oe[2] = 1'b0 ;
   assign uio_oe[3] = 1'b0 ;
   assign uio_oe[4] = 1'b0 ;
   assign uio_oe[5] = 1'b0 ;
   assign uio_oe[6] = 1'b0 ;
   assign uio_oe[7] = 1'b0 ;
   assign uio_out[0] = 1'b0 ;
   assign uio_out[1] = 1'b0 ;
   assign uio_out[2] = 1'b0 ;
   assign uio_out[3] = 1'b0 ;
   assign uio_out[4] = 1'b0 ;
   assign uio_out[5] = 1'b0 ;
   assign uio_out[6] = 1'b0 ;
   assign uio_out[7] = 1'b0 ;

   tensor_core_controller tc_inst (.clock_in(clk),
	.reset_in(n_0),
	.current_instruction({ UNCONNECTED_HIER_Z4,
		UNCONNECTED_HIER_Z3,
		UNCONNECTED_HIER_Z2,
		uio_in[4],
		uio_in[3],
		uio_in[2],
		uio_in[1],
		uio_in[0],
		UNCONNECTED_HIER_Z1,
		UNCONNECTED_HIER_Z0,
		UNCONNECTED_HIER_Z,
		ui_in[4],
		ui_in[3],
		ui_in[2],
		ui_in[1],
		ui_in[0] }),
	.tensor_core_controller_output(uo_out));
   INVX2 g2 (.Y(n_0),
	.A(rst_n));
